using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments").RequireAuthorization();

        // Get all shipments (dispatchers see all, customers see their own)
        group.MapGet("/", async (ApplicationDbContext db, HttpContext context, UserManager<ApplicationUser> userManager) =>
        {
            var user = await userManager.GetUserAsync(context.User);
            if (user is null) return Results.Unauthorized();

            var isDispatcher = await userManager.IsInRoleAsync(user, "Dispatcher");

            var query = isDispatcher
                ? db.Shipments.AsQueryable()
                : db.Shipments.Where(s => s.CustomerEmail == user.Email);

            var shipments = await query
                .OrderByDescending(s => s.ShippedDate)
                .Select(s => new ShipmentDto
                {
                    Id = s.Id,
                    TrackingNumber = s.TrackingNumber,
                    Origin = s.Origin,
                    Destination = s.Destination,
                    Status = s.Status,
                    ShippedDate = s.ShippedDate,
                    EstimatedDelivery = s.EstimatedDelivery,
                    ActualDelivery = s.ActualDelivery,
                    CustomerEmail = s.CustomerEmail,
                    Description = s.Description
                })
                .ToListAsync();

            return Results.Ok(shipments);
        });

        // Track a shipment by tracking number (public)
        app.MapGet("/api/shipments/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments
                .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);

            if (shipment is null)
                return Results.Ok(new TrackingResult { Found = false, ErrorMessage = "Shipment not found." });

            return Results.Ok(new TrackingResult
            {
                Found = true,
                Shipment = new ShipmentDto
                {
                    Id = shipment.Id,
                    TrackingNumber = shipment.TrackingNumber,
                    Origin = shipment.Origin,
                    Destination = shipment.Destination,
                    Status = shipment.Status,
                    ShippedDate = shipment.ShippedDate,
                    EstimatedDelivery = shipment.EstimatedDelivery,
                    ActualDelivery = shipment.ActualDelivery,
                    Description = shipment.Description
                }
            });
        });

        // Create a shipment (dispatchers only)
        group.MapPost("/", async (CreateShipmentRequest request, ApplicationDbContext db, HttpContext context, UserManager<ApplicationUser> userManager) =>
        {
            var user = await userManager.GetUserAsync(context.User);
            if (user is null) return Results.Unauthorized();

            var isDispatcher = await userManager.IsInRoleAsync(user, "Dispatcher");
            if (!isDispatcher) return Results.Forbid();

            var shipment = new Shipment
            {
                TrackingNumber = GenerateTrackingNumber(),
                Origin = request.Origin,
                Destination = request.Destination,
                CustomerEmail = request.CustomerEmail,
                Description = request.Description,
                Status = ShipmentStatus.Pending,
                ShippedDate = DateTime.UtcNow,
                EstimatedDelivery = request.EstimatedDelivery
            };

            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();

            return Results.Created($"/api/shipments/{shipment.Id}", new ShipmentDto
            {
                Id = shipment.Id,
                TrackingNumber = shipment.TrackingNumber,
                Origin = shipment.Origin,
                Destination = shipment.Destination,
                Status = shipment.Status,
                ShippedDate = shipment.ShippedDate,
                EstimatedDelivery = shipment.EstimatedDelivery,
                CustomerEmail = shipment.CustomerEmail,
                Description = shipment.Description
            });
        });

        // Update shipment status (dispatchers only)
        group.MapPut("/{id:int}/status", async (int id, UpdateShipmentStatusRequest request, ApplicationDbContext db, HttpContext context, UserManager<ApplicationUser> userManager) =>
        {
            var user = await userManager.GetUserAsync(context.User);
            if (user is null) return Results.Unauthorized();

            var isDispatcher = await userManager.IsInRoleAsync(user, "Dispatcher");
            if (!isDispatcher) return Results.Forbid();

            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();

            shipment.Status = request.Status;
            if (request.Status == ShipmentStatus.Delivered)
                shipment.ActualDelivery = DateTime.UtcNow;

            await db.SaveChangesAsync();
            return Results.NoContent();
        });
    }

    private static string GenerateTrackingNumber()
    {
        return $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Guid.NewGuid().ToString()[..8].ToUpper()}";
    }
}

