@page "/track"
@page "/track/{TrackingNumber}"
@using ShipmentTracker.Client.Models
@inject HttpClient Http

<PageTitle>Track Shipment</PageTitle>

<h2>📋 Track Your Shipment</h2>

<div class="row mb-4">
    <div class="col-md-8">
        <div class="input-group">
            <input type="text" class="form-control form-control-lg"
                   placeholder="Enter tracking number (e.g., SHP-20260101-A1B2C3D4)"
                   @bind="searchTrackingNumber" @bind:event="oninput"
                   @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary btn-lg" @onclick="TrackShipment" disabled="@isSearching">
                @if (isSearching)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Track
            </button>
        </div>
    </div>
</div>

@if (result is not null)
{
    @if (result.Found && result.Shipment is not null)
    {
        var s = result.Shipment;
        <div class="card shadow">
            <div class="card-header bg-primary text-white">
                <h4 class="mb-0">Shipment: @s.TrackingNumber</h4>
            </div>
            <div class="card-body">
                <div class="row g-3">
                    <div class="col-md-6">
                        <h6 class="text-muted">Status</h6>
                        <span class="badge fs-6 @GetStatusBadgeClass(s.Status)">@s.Status</span>
                    </div>
                    <div class="col-md-6">
                        <h6 class="text-muted">Description</h6>
                        <p>@s.Description</p>
                    </div>
                    <div class="col-md-6">
                        <h6 class="text-muted">Origin</h6>
                        <p>@s.Origin</p>
                    </div>
                    <div class="col-md-6">
                        <h6 class="text-muted">Destination</h6>
                        <p>@s.Destination</p>
                    </div>
                    <div class="col-md-4">
                        <h6 class="text-muted">Shipped Date</h6>
                        <p>@s.ShippedDate.ToString("MMM dd, yyyy")</p>
                    </div>
                    <div class="col-md-4">
                        <h6 class="text-muted">Estimated Delivery</h6>
                        <p class="fw-bold text-primary">@(s.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "TBD")</p>
                    </div>
                    <div class="col-md-4">
                        <h6 class="text-muted">Actual Delivery</h6>
                        <p>@(s.ActualDelivery?.ToString("MMM dd, yyyy") ?? "—")</p>
                    </div>
                </div>

                <!-- Progress indicator -->
                <div class="mt-4">
                    <h6>Shipment Progress</h6>
                    <div class="progress" style="height: 30px;">
                        <div class="progress-bar @GetProgressBarClass(s.Status)"
                             role="progressbar"
                             style="width: @GetProgressPercentage(s.Status)%"
                             aria-valuenow="@GetProgressPercentage(s.Status)"
                             aria-valuemin="0" aria-valuemax="100">
                            @s.Status
                        </div>
                    </div>
                </div>
            </div>
        </div>
    }
    else
    {
        <div class="alert alert-warning">
            <strong>Not Found:</strong> @(result.ErrorMessage ?? "No shipment found with that tracking number.")
        </div>
    }
}

@code {
    [Parameter]
    public string? TrackingNumber { get; set; }

    private string searchTrackingNumber = "";
    private bool isSearching;
    private TrackingResult? result;

    protected override async Task OnParametersSetAsync()
    {
        if (!string.IsNullOrEmpty(TrackingNumber))
        {
            searchTrackingNumber = TrackingNumber;
            await TrackShipment();
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(searchTrackingNumber)) return;

        isSearching = true;
        result = null;

        result = await Http.GetFromJsonAsync<TrackingResult>(
            $"/api/shipments/track/{Uri.EscapeDataString(searchTrackingNumber.Trim())}");

        isSearching = false;
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Returned => "bg-dark",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Returned => "bg-dark",
        _ => "bg-primary"
    };

    private static int GetProgressPercentage(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 25,
        ShipmentStatus.InTransit => 50,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 50,
        ShipmentStatus.Returned => 100,
        _ => 0
    };
}

@page "/myshipments"
@using ShipmentTracker.Client.Models
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@inject HttpClient Http

<PageTitle>My Shipments</PageTitle>

<h2>📦 My Shipments</h2>

@if (isLoading)
{
    <p><em>Loading your shipments...</em></p>
}
else if (shipments is null || !shipments.Any())
{
    <div class="alert alert-info">
        You don't have any shipments yet. Use the <a href="track">Track</a> page to look up a shipment by tracking number.
    </div>
}
else
{
    <div class="row g-4">
        @foreach (var shipment in shipments)
        {
            <div class="col-md-6 col-lg-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-header d-flex justify-content-between">
                        <code>@shipment.TrackingNumber</code>
                        <span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span>
                    </div>
                    <div class="card-body">
                        <p><strong>From:</strong> @shipment.Origin</p>
                        <p><strong>To:</strong> @shipment.Destination</p>
                        <p><strong>Description:</strong> @shipment.Description</p>
                        <hr />
                        <p class="mb-1"><small class="text-muted">Shipped: @shipment.ShippedDate.ToString("MMM dd, yyyy")</small></p>
                        <p class="mb-0">
                            <strong>Est. Delivery:</strong>
                            <span class="text-primary">@(shipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "TBD")</span>
                        </p>
                        @if (shipment.ActualDelivery.HasValue)
                        {
                            <p class="text-success mt-1 mb-0">
                                ✅ Delivered: @shipment.ActualDelivery.Value.ToString("MMM dd, yyyy")
                            </p>
                        }
                    </div>
                    <div class="card-footer">
                        <a href="track/@shipment.TrackingNumber" class="btn btn-sm btn-outline-primary">View Details</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private List<ShipmentDto>? shipments;
    private bool isLoading = true;

    protected override async Task OnInitializedAsync()
    {
        shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments");
        isLoading = false;
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Returned => "bg-dark",
        _ => "bg-secondary"
    };
}

